// Parse expiring domains and score by SEO value signals
// In production, integrate with Moz/Ahrefs API for DA/DR scores
const html = $input.item.json.data || '';

// Extract domain data from HTML table rows
const domainPattern = /([a-z0-9-]+\.[a-z]{2,})/gi;
const domains = [...new Set((html.match(domainPattern) || []).slice(0, 100))];

// Score heuristics (replace with real API calls in production)
const scored = domains.map(domain => {
  const parts = domain.split('.');
  const name = parts[0];
  const tld = parts.slice(1).join('.');

  let score = 0;
  // Short domains are more valuable
  if (name.length <= 5) score += 3;
  else if (name.length <= 8) score += 2;
  else if (name.length <= 12) score += 1;

  // .com premium
  if (tld === 'com') score += 3;
  else if (tld === 'io' || tld === 'co') score += 2;

  // Keyword value (basic heuristic)
  const keywords = ['ai', 'app', 'tool', 'auto', 'bot', 'data', 'cloud', 'dev', 'tech', 'smart', 'pay', 'cash', 'shop'];
  for (const kw of keywords) {
    if (name.includes(kw)) { score += 2; break; }
  }

  // No numbers or hyphens preferred
  if (!/[-0-9]/.test(name)) score += 1;

  return {
    domain,
    name,
    tld,
    score,
    estimatedBuyCost: 10 + Math.floor(Math.random() * 40),
    estimatedResaleValue: score >= 6 ? 500 + score * 200 : 100 + score * 50,
    scannedAt: new Date().toISOString()
  };
});

// Sort by score descending, take top 20
scored.sort((a, b) => b.score - a.score);
const topDomains = scored.slice(0, 20);

return [{ json: { domains: topDomains, totalScanned: domains.length, date: new Date().toISOString().split('T')[0] } }];

const data = $input.item.json;
const highValue = data.domains.filter(d => d.score >= 5 && d.estimatedResaleValue > 200);

return [{
  json: {
    opportunities: highValue,
    count: highValue.length,
    totalScanned: data.totalScanned,
    date: data.date,
    topPick: highValue[0] || null
  }
}];

